import re
content = open('data/toolsData.ts').read()

injected = 0
for category, tools in new_tools.items():
    tools_block = ""
    for t in tools:
        line = f'\n      {{ id: "{t["id"]}", name: "{t["name"]}", description: "{t["description"]}", url: "{t["url"]}", upvotes: {t["upvotes"]}, verified: {"true" if t["verified"] else "false"}, rating: {t["rating"]}, icon: "{t["icon"]}", category: "{category}", subcategory: "{t["subcategory"]}" }},'
        tools_block += line

    pattern = f'"{category}": {{'
    idx = content.find(pattern)
    if idx == -1:
        print(f"⚠️  Category not found: {category}")
        continue
    bracket_idx = content.find("[", idx)
    if bracket_idx == -1:
        continue
    content = content[:bracket_idx+1] + tools_block + "\n" + content[bracket_idx+1:]
    injected += len(tools)
    print(f"✅ Added {len(tools)} tools to {category}")

open('data/toolsData.ts', 'w').write(content)
print(f"\n✅ Done! {injected} tools injected into toolsData.ts")
